CREATE VIEW `ads_grant_user_giftlog_view` (`dt` COMMENT "create 分区", `product_id` COMMENT "产品id", `id` COMMENT "自增id", `op_type` COMMENT "状态，1：发放 2：过期", `user_id` COMMENT "用户id", `gift_num` COMMENT "算发放与过期的礼券或赠送币的数量 统一用gift_num字段", `expire_time` COMMENT "过期时间", `source` COMMENT "来源", `send_num` COMMENT "发放数量", `send_time` COMMENT "发放时间", `gift_type` COMMENT "货币类型 0：礼券 1：赠送币", `create_time` COMMENT "创建时间", `appid` COMMENT "应用程序id", `position_id` COMMENT "空字段", `app_game_id` COMMENT "记录游戏发放礼券", `source_key` COMMENT "来源key", `source_args`, `ModuleSendId`, `etl_time` COMMENT "etl清洗时间")
